        EP_HOST_ASSERT(num_tokens == num_tokens_);
        EP_HOST_ASSERT(sf->is_cuda());
        EP_HOST_ASSERT(sf->element_size() == sizeof(sf_pack_t));
        num_sf_packs = num_sf_packs_;
        sf_ptr = sf->data_ptr();
        sf_token_stride = sf->stride(0);
        sf_hidden_stride = sf->stride(1);
